// COMPLETE, COMPILABLE C code
#include <stdio.h>
#include <stdbool.h>
#define MAX_N 1000001
bool isPrime[MAX_N];
void sieveOfEratosthenes() {
    for (int i = 0; i < MAX_N; i++) {
        isPrime[i] = true;
    }
    isPrime[0] = isPrime[1] = false;
    for (int i = 2; i * i < MAX_N; i++) {
        if (isPrime[i]) {
            for (int j = i * i; j < MAX_N; j += i) {
                isPrime[j] = false;
            }
        }
    }
}
int countPrimePairs(int N) {
    int count = 0;
    for (int a = 0; a <= N; a++) {
        for (int b = a; b <= N; b++) {
            if (isPrime[a] && isPrime[b] && a + b == N) {
                count++;
            }
        }
    }
    return count;
}
int main() {
    sieveOfEratosthenes();
    int T;
    scanf("%d", &T);
    while (T--) {
        int N;
        scanf("%d", &N);
        int fN = countPrimePairs(N);
        int count = 0;
        for (int a = 0; a < N; a++) {
            for (int b = a; b < N; b++) {
                int fa = countPrimePairs(a);
                int fb = countPrimePairs(b);
                if (fa + fb == fN) {
                    count++;
                }
            }
        }
        printf("%d\n", count);
    }
    return 0;
}

